#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

int main()
{
	long long a,c,b[10001]={ };
	cin>>a;
	for(int i=1;i<=a;i++){
		cin>>b[i];
	}
	cin>>c;
	for(int i=1;i<=a;i++){
		if(b[i]==c){
			cout<<i-1<<endl;
			return 0;
		}
	}
	cout<<"-1";
	return 0;
}
